fullOutput:
    font-family: monospace;
    font-size: 18px;
    text-align: center;
}

.ascii-table .control-char {
    color: var(--warning);
}

.ascii-table .printable-char {
    color: var(--success);
}

.ascii-table .extended-char {
    color: var(--primary);
}

    .markdown-container,
    .diff-container {
        grid-template-columns: 1fr;
    }

    .jwt-sections {
        grid-template-columns: 1fr;
    }

    .cron-builder {
        grid-template-columns: 1fr;
    }
}
